# Get the script directory
my $script_dir = dirname(abs_path($0));

# Navigate up three levels from the script directory
my $target_dir = abs_path("$script_dir/../../..");

# Create the directory if it doesn't exist
my $dir_path = "$target_dir/_testing/sm_run";
make_path($dir_path);

# Create the debug file
my $debug_file = "$dir_path/perl.debug";
touch($debug_file);

# Change permissions to 777 recursively
chmod '0777', $target_dir . "/_testing";
